        expect(menu.hidden).toBe(false);

        window.dispatchEvent(new Event('scroll'));

        expect(menu.hidden).toBe(true);
        expect(btn.getAttribute('aria-expanded')).toBe('false');
      });

      it('registers the scroll listener in the capture phase so inner-container scrolls are caught', async () => {
        const { results } = await setupCleared();
        renderBrowse(browseResult({ path: 'docs', entries: [file] }));

        const addSpy = vi.spyOn(window, 'addEventListener');

        menuBtnOf(actionsOf(results, 'a.txt')).click();

        // Exactly one scroll listener, registered on window with useCapture=true.
        const scrollAdds = addSpy.mock.calls.filter((c) => c[0] === 'scroll');
        expect(scrollAdds).toHaveLength(1);
        expect(scrollAdds[0][1]).toBeTypeOf('function');
        expect(scrollAdds[0][2]).toBe(true);
      });

      it('removes the scroll and resize listeners when the menu closes (matching capture flag)', async () => {
        const { results } = await setupCleared();
        renderBrowse(browseResult({ path: 'docs', entries: [file] }));

        menuBtnOf(actionsOf(results, 'a.txt')).click();

        const removeSpy = vi.spyOn(window, 'removeEventListener');
        document.dispatchEvent(new KeyboardEvent('keydown', { key: 'Escape' }));

        // The capture flag passed to removeEventListener MUST match the one
        // used at registration (true for scroll) or the listener is not
        // actually detached.
        const scrollRemoves = removeSpy.mock.calls.filter((c) => c[0] === 'scroll');
        expect(scrollRemoves).toHaveLength(1);
        expect(scrollRemoves[0][1]).toBeTypeOf('function');
        expect(scrollRemoves[0][2]).toBe(true);

        const resizeRemoves = removeSpy.mock.calls.filter((c) => c[0] === 'resize');
        expect(resizeRemoves).toHaveLength(1);
        expect(resizeRemoves[0][1]).toBeTypeOf('function');
      });

      it('scroll/resize dispatches after close are a no-op (listeners were torn down)', async () => {
        const { results } = await setupCleared();
        renderBrowse(browseResult({ path: 'docs', entries: [file] }));

        const actions = actionsOf(results, 'a.txt');
        const btn = menuBtnOf(actions);
        const menu = menuOf(actions);

        btn.click();
        expect(menu.hidden).toBe(false);
        document.dispatchEvent(new KeyboardEvent('keydown', { key: 'Escape' }));
        expect(menu.hidden).toBe(true);

        // After teardown these must not throw and must leave the menu closed.
        window.dispatchEvent(new Event('scroll'));
        window.dispatchEvent(new Event('resize'));
        results.dispatchEvent(new Event('scroll'));

        expect(menu.hidden).toBe(true);
        expect(btn.getAttribute('aria-expanded')).toBe('false');
      });

      it('still closes on Escape and outside-click with the scroll/resize listeners active', async () => {
        const { results } = await setupCleared();
        renderBrowse(browseResult({ path: 'docs', entries: [file] }));

        const actions = actionsOf(results, 'a.txt');
        const btn = menuBtnOf(actions);
        const menu = menuOf(actions);

        btn.click();
        expect(menu.hidden).toBe(false);

        document.dispatchEvent(new KeyboardEvent('keydown', { key: 'Escape' }));
        expect(menu.hidden).toBe(true);
        expect(btn.getAttribute('aria-expanded')).toBe('false');

        // Re-open and confirm the outside-click dismissal path still works.
        btn.click();
        expect(menu.hidden).toBe(false);

        const outside = document.createElement('div');
        document.body.append(outside);
        outside.click();
        outside.remove();

        expect(menu.hidden).toBe(true);
        expect(btn.getAttribute('aria-expanded')).toBe('false');
      });
    });

